var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"내가 들은 그 말들이 전부 사실이겠지, 피터?","JPN":"わしが聞いた言葉は全て事実じゃろう、ピーター。","ENG":"Everything I just heard has gotta be true, right Peter?","TWN":"我聽到的那些話都是事實的吧，彼得？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그렇긴 한데… 아무래도 기억 자체가 온전하지 못한 것 같았어요.","JPN":"そうですけど……どうやら記憶自体が完全じゃないようでしたよ。","ENG":"Yes, but... I think his memories aren't fully intact.","TWN":"話雖如此……但我看他好像失去記憶一樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"마치 과거에 살다가 온 사람처럼…","JPN":"まるで過去から来た人みたいに……","ENG":"It's as if he's been living in the past...","TWN":"感覺就像從過去來到現代的人…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"큐리안이면 그 실종됐다던 총사대장 아냐?","JPN":"キュリアンって、あの行方不明になったっていう銃士隊長じゃないか？","ENG":"\\"Curian\\"? Isn't that the General Musketeer who went missing?","TWN":"庫里安不就是那個失蹤的隊長嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가 수상하긴 했어. 왕실 군복 차림에 병기마까지 타고 있었다며.","JPN":"どこか怪しいと思ったのよ。王室の軍服姿で、兵器馬にまで乗ってたらしいじゃない。","ENG":"I knew something was up. Wasn't he wearing the Royal Army uniform and riding on an Armored Horse?","TWN":"確實有點可疑，聽說他身穿皇家軍裝，還騎在戰馬上。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"20년 전 사람이 왜 이제서야 여기 나타나? 뭔가 착각한 거겠지.","JPN":"20年の前の人間がなんで今更ここに現れるんだ？　何かの間違いだろう。","ENG":"But why would a person from 20 years ago suddenly appear here? I'm sure there must be an explanation for all of this.","TWN":"二十年前的人怎麼現在才出現在這裡？應該哪裡有誤會吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"사실이라면 당장 내쫓아야 하는 거 아녜요? 재건단 사람들에게 오해 받긴 싫다고요.","JPN":"本当なら今すぐ追い出さなきゃダメなんじゃないですか？　再建団の人たちに誤解されたくないわ。","ENG":"If what he says is true, shouldn't we immediately kick him out? I don't want the Alliance people to get the wrong idea.","TWN":"如果是真的，那應該馬上把他趕出去吧？我不才想被重建委員會的人誤會。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"내쫓긴 뭘 내쫓아? 당장 끌고가서 심판을 받게 해야지!","JPN":"追い出すも何も、今すぐ捕まえて審判するべきだよ！","ENG":"What do you mean \\"kick him out\\"? We should drag him out and bring him judgment!","TWN":"怎麼可以把他趕走？要馬上把他抓去受審吧！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"피터, 수비대를 불러라.","JPN":"ピーター、守備隊を呼びなさい。","ENG":"Peter, call the guards.","TWN":"彼得，叫護衛隊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그럼… 저 사람은 어떻게 되는 거죠?","JPN":"じゃあ……あの人はどうなるんですか？","ENG":"Then... What's gonna happen to him?","TWN":"那…他會變成怎樣？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"제라드 큐리안은 국가지명수배자다. 군법에 따라 재판을 받게 해야지.","JPN":"ジェラード・キュリアンは国家指名手配犯だ。軍法に従って裁判しなければ。","ENG":"Gerard Curian is a wanted criminal. He'll be tried according to military law.","TWN":"傑瑞德· 庫里安是國家通緝犯，應該按照軍法受審。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"촌장님! 놈은 열쇠를 가지고 도망친 배신자라고요!","JPN":"村長！　やつは鍵を持って逃げた裏切り者ですよ！","ENG":"But Chief! He's the traitor who ran away with the Key!","TWN":"村長！這傢伙是拿走鑰匙逃跑的叛徒！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"우리가 써야 할 약으로 치료해 준 것도 열불나는데 감옥에서 여생을 보내게 해 준다니요?","JPN":"治療に私たちの薬を使ったのも腹立たしいのに、牢獄で余生を送ることを許すなんて！","ENG":"We've already wasted precious medicine in treating this traitor! But now you want us to let him rot in jail for the rest of his life?!","TWN":"竟然把我們要用的藥拿去給他治療，怎麼可以讓他在監獄裡度過餘生這麼好過？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"옳소! 이런 법이 어디 있습니까!","JPN":"そうだ！　どういうことですか！","ENG":"Yeah! What kind of justice is that?!","TWN":"沒錯！哪有這種事！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"읏!","JPN":"うっ！","ENG":"Ngh!","TWN":"呃！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"상처가 아직도 안 아물었나?","JPN":"傷がまだ治ってないのね。","ENG":"It still hasn't healed?","TWN":"傷口還沒好嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"카운터라는 것도 이럴 때는 정말이지 쓸모가 없군.","JPN":"カウンターってのもこんな時にはまったく役に立たないね。","ENG":"I guess being a Counter is pretty useless at times like this.","TWN":"在這種時候，就算是制裁者也沒什麼用嘛。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"대장님, 전해 드릴 말씀이… 음?","JPN":"隊長、話が……うん？","ENG":"Captain, there's something I need to– Hmm?","TWN":"報告隊長… 嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭡니까, 그건?","JPN":"なんですか、それは。","ENG":"What's that?","TWN":"那是什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"화살. 시간이 있을 때 미리 깎아 둬야지.","JPN":"矢。時間がある時に削っておかないと。","ENG":"An arrow. Gotta make them while you can.","TWN":"箭，要趁有空的時候先做起來預備才行。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아뇨. 쓰레기통 안의 그 피투성이 붕대 말입니다.","JPN":"そうではなく。ゴミ箱の中の血まみれの包帯のことです。","ENG":"No, not that. The bloody bandages in the trash.","TWN":"不是，我是說垃圾桶裡血跡斑斑的繃帶。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"역시 어제 폭발에 휘말렸을 때 다치신 겁니까?","JPN":"やはり昨日爆発に巻き込まれた時、怪我をされたのでは？","ENG":"Did you get hurt in the explosion yesterday?","TWN":"果然是昨天爆炸時受的傷嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아니. 치료를 제대로 안 한 내 실수야. 화약을 덜 씻었는지 상처가 덧나 버렸어.","JPN":"いや。ちゃんと手当てをしなかった私のミスだ。火薬の洗い残しがあったのか、傷が悪化してしまった。","ENG":"No. It's my fault for not treating it properly. Must be because of some gunpowder residue it hasn't healed yet.","TWN":"不是，是我自己沒有好好接受治療，可能是火藥沒清乾淨，導致傷口發炎。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"너에겐 못 볼 꼴을 보였네.","JPN":"みっともないところを見せてしまったな。","ENG":"You weren't supposed to see that.","TWN":"讓你看到我這麼狼狽的樣子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런데 바깥이 왜 이리 소란스럽지?","JPN":"ところで、外が騒がしいようだが？","ENG":"But what's with all the ruckus outside?","TWN":"不過外面怎麼這麼吵？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아, 이번 전투에서 구조하신 환자 있잖습니까.","JPN":"あ、今回の戦闘で救助した患者のことで。","ENG":"Oh, the patient we rescued during battle...","TWN":"喔，你不是在這次作戰中有救出來一名傷患嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그 자가 본인 스스로를 큐리안이라고 하더군요.","JPN":"あの者、自分がキュリアンだと名乗りました。","ENG":"He's claiming that he is Gerard Curian.","TWN":"他自稱是庫里安。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"큐리안……?","JPN":"キュリアン……？","ENG":"Curian...?","TWN":"庫里安……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"진정들 해. 나도 자네들 마음을 이해하지 못하는 건 아닐세.","JPN":"落ち着きなさい。わしもお前さんたちの気持ちはわからんでもない。","ENG":"Calm yourselves. I can understand why you are all so angry.","TWN":"大家冷靜點，我不是不明白你們的心情。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"하지만 그렇다 해서 우리가 진상을 밝히고 심판할 입장은 아니지 않나?","JPN":"しかし、じゃからといってわしらが真相を明かして審判する立場ではあるまい。","ENG":"However, shouldn't there be a trial to uncover the truth before sentencing him to death?","TWN":"但就算如此，但我們沒有立場可以審判人，"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"저 자의 처우는 군인들에게 맡기는 수밖에 없네.","JPN":"あの者の処遇は軍人に任せるしかないんじゃ。","ENG":"We have no choice but to leave this man's fate to the soldiers.","TWN":"只能將他交給軍隊處置。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"아뇨! 전 그렇게는 못하겠습니다! 지금 당장 놈을 끌어내야겠습니다!","JPN":"いいえ！　私はそうできません！　今すぐやつを引きずりだすべきだ！","ENG":"No! I can't accept that! We should take matter into our own hands!","TWN":"不！我不同意！立刻把那傢伙帶出來！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"놈이 자기 죄를 인정하든 하지 않든……!","JPN":"やつが自分の罪を認めようが認めまいが……！","ENG":"It doesn't matter if he admits he's guilty or not...!","TWN":"我管他認不認罪……！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"인정하지 않으면 어떻게 할 셈이지?","JPN":"認めなかったらどうするつもりなんだ？","ENG":"Then what will you do if he doesn't?","TWN":"如果不認罪你想怎麼辦？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"에, 엘라 대장님?","JPN":"え、エラ隊長？","ENG":"C-captain Ella?","TWN":"艾…艾拉隊長？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"대장님! 놈은 제라드 큐리안입니다! 대장님도 그 자가 누군지 잘 아시잖습니까!","JPN":"隊長！　やつはジェラード・キュリアンです！　隊長もどんなやつかはよく知ってるじゃないですか！","ENG":"Captain! That man is Gerard Curian! You know who that man is better than all of us!","TWN":"隊長！這傢伙是傑瑞德· 庫里安！隊長也知道他是誰吧！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"창 한 자루로 내로라하는 카운터를 모두 꺾고 총사대 서열 1위에 오른 영웅 중의 영웅이지.","JPN":"槍一本で名のあるカウンターを全て破り、銃士隊の序列1位となった英雄の中の英雄。","ENG":"A Counter, and a hero among heroes who rose to the top of the Musketeer Division with nothing but a spear.","TWN":"單憑一把槍便擊敗所有出色的制裁者，在射擊隊中排名第一，是英雄中的英雄。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신은 이 환자를 그 자라고 주장하고 싶은 거야?","JPN":"あなたはこの患者がその者だと言い張りたいのか？","ENG":"Do you wish to imply that this patient is that man?","TWN":"你是想說這個病患是他嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"병기마는 총사대만의 특권이었으니까요!","JPN":"兵器馬は銃士隊だけの特権でしたから！","ENG":"But Armored Horses were only given to members of the Musketeer Division!","TWN":"因為戰馬是射擊隊的專屬特權！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"그리고 총사대의 카운터들은 20년 전 전쟁에서 모두 죽었어요!","JPN":"それに、銃士隊のカウンターは20年前の戦争でみんな死にました！","ENG":"And all Counters of the Division died in the war 20 years ago!","TWN":"而且射擊隊的制裁者，在20年前的戰爭中便已全數陣亡！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"열쇠를 가지고 사라진 큐리안 한 명만을 제외하고 말입니다!","JPN":"鍵を持ったまま消えたキュリアン、ただ一人を除いて！","ENG":"All except for Curian, who stole the Key and went missing!","TWN":"只剩一個帶著鑰匙消失的庫里安！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"병기마를 타고 나타나서 자기를 큐리안이라고 하는데, 무슨 증거가 더 필요합니까?!","JPN":"兵器馬に乗って現れて、自分がキュリアンだと言うのに、他になんの証拠が必要なんですか！","ENG":"He showed up on an Armored Horse and claims that he is Curian! What more evidence do we need?!","TWN":"騎著戰馬出現，還說自己是庫里安，這還需要什麼證據嗎？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"잠깐, 총사대가 모두 전사했다고? 게다가 20년 전이라니?","JPN":"待て、銃士隊がみんな戦死しただと？　しかも20年前？","ENG":"Wait, everyone in the Musketeer Division died? 20 years ago?","TWN":"等等，你說射擊隊全數陣亡？而且是20年前？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"뭔가 오해한 것 아닌가? 떠오르는 건 전부 얘기할 테니…","JPN":"何か誤解してないか？　思い出せることは全部話すから……","ENG":"That can't be right. I'll tell you everything I kn─","TWN":"是不是哪裡有誤會？我只是把我想到的都說出來…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"…커헉!","JPN":"……ぐはっ！","ENG":"Kuh...!","TWN":"…咳咳！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"자, 방금 이 자가 내 주먹에 반응했나?","JPN":"さて、たった今この者が私のげんこつに反応したか？","ENG":"Now, did this man react to my punch?","TWN":"你們看，這傢伙剛才有閃過我的拳頭嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"주먹질 한 번에 코피를 흘리면서 쓰러진 이 자가, 당신이 말한 총사대 서열 1위라고?","JPN":"げんこつ一発に鼻血を流しながら倒れたこの者が、あなたの言った銃士隊の序列1位だと？","ENG":"You're saying that this man, who was knocked out by a single punch, is the Musketeer Division's strongest soldier?","TWN":"不過才一拳就流鼻血暈倒的傢伙，你說他是射擊隊中排名第一？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내 눈에는 아무 능력도 없는 평범한 인간으로 보이는데.","JPN":"私の目にはなんの能力もない、ただの人間にしか見えないんだが。","ENG":"All I see is an ordinary man.","TWN":"在我看來，他不過就是個平凡人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"그… 그건…….","JPN":"そ……それは……","ENG":"Th-that's...","TWN":"那… 那是……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"어떻게 된 거야? 성자라면 엘라 대장이랑 같은 카운터 아냐?","JPN":"どうなったんだ？　聖者ならエラ隊長と同じカウンターじゃないか？","ENG":"I don't get it. Aren't Helgons supposed to be Counters like Captain Ella?","TWN":"怎麼搞的？聖者的話，不是和艾拉隊長一樣是制裁者嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"살짝 친 것 같은데, 깃털처럼 날아가버렸어.","JPN":"軽く殴ったように見えたけど、羽のように飛んでいったぞ。","ENG":"She barely even punched him and he's knocked out cold.","TWN":"怎麼會這麼不堪一擊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"죽다 살아난 환자가 기억이 왜곡되어 착각을 일으키는 건 흔한 일이야.","JPN":"死にかけた患者の記憶が歪曲されて、錯覚を起こすのはよくあることだ。","ENG":"After a near-death experience, it is not uncommon for patients to become delusional and have their memories distorted.","TWN":"一個從鬼門關走過一遭的病患，通常在記憶上會產生一些錯覺，這是很常見的事情。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신들이 화를 내는 이유는 이해하지만, 무고한 인간까지 휘말리게 하진 마.","JPN":"あなたたちが腹を立てる理由はわかるが、無実の人間まで巻き込むな。","ENG":"I understand why you're upset, but don't take it out on someone who isn't guilty.","TWN":"我可以理解你們為何生氣，但不要遷怒於無辜的人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Krrgh...","TWN":"咳……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"대장님, 저 사람들은 제가 잘 타이르겠습니다. 그만하시죠.","JPN":"隊長、あの者たちにはわしがちゃんと言い聞かせます。ここまでにしましょう。","ENG":"Captain, stop. Please allow me to calm the people down.","TWN":"隊長，我會好好勸大家的，就到此為止吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_NULL_ANGER","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"알겠어. 그럼 이 환자는 내가 다시 데려갈게.","JPN":"わかった。では、この患者は私が連れていく。","ENG":"All right. Then I'll be taking my patient back to his room.","TWN":"好，那個人我會帶走。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"여기서 한 발짝도 나올 생각 말고 회복에만 집중해.","JPN":"ここから出る考えなど捨て、回復に集中して。","ENG":"Don't step a foot outside this room. Just focus on recovering.","TWN":"別想踏出這裡一步，專心休養身體吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"심심하면 여기 있는 나뭇가지들로 화살이나 깎든가.","JPN":"暇だったらここにある木の枝で矢でも作って。","ENG":"If you're bored, you can make arrows out of these twigs.","TWN":"無聊的話，可以拿這裡的樹枝削成箭。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"끄응…… 주먹이 맵군, 엘라 대장.","JPN":"ぐうう……げんこつは痛烈だった、エラ隊長。","ENG":"*Groan* You got a mean punch, Captain Ella.","TWN":"唔……你的拳頭好硬，艾拉隊長。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내 이름은 누구에게 들었지?","JPN":"私の名前は誰から聞いた？","ENG":"Who told you my name?","TWN":"誰告訴你我的名字的？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"피터란 소년에게서. 죽어가던 날 자네가 치료해 줬다더군.","JPN":"ピーターという少年から。死にかけていた日、君が私を治療してくれたと。","ENG":"The boy, Peter. He told me you were the one who treated me.","TWN":"是那個叫彼得的年輕人告訴我的。他說在我差點死掉那天，是你替我治療的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"죽게 내버려 둘 순 없었으니까. 고마워하진 않아도 돼.","JPN":"死にゆくままにするわけにはいかなかったから。ありがたく思うことはない。","ENG":"There's no need to thank me. I couldn't just leave you to die.","TWN":"因爲我不能見死不救，無需謝我。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……그보다 코피가 멈추지 않는데.","JPN":"……それより鼻血が止まらないんだが。","ENG":"However, my nosebleed isn't stopping.","TWN":"……不過，我的鼻血好像流不停。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 피라도 흘렸으니까 사람들이 진정한 거야. 힘 조절은 했으니 걱정 마.","JPN":"血でも流したからみんな落ち着いたんだ。力加減はしたから心配しなくていい。","ENG":"It was just a tap on the nose. Plus, it's because you bleed that the villagers have calmed down.","TWN":"就是因為你流血，大家才冷靜下來的。我有拿捏力氣，放心吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 일이라면 내가 설명하게 놔두는 편이 나았을 거다.","JPN":"そのことなら、私が説明するようにした方が良かったと思うんだが。","ENG":"You should've just let me explain.","TWN":"那件事由我來解釋會比較好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나는 폐하의 명에 따라 임무를 수행했을 뿐, 열쇠를 훔친 적은 없어.","JPN":"私は陛下の命令に従って任務を遂行しただけで、鍵を盗んだことはない。","ENG":"I was on a mission on His Majesty's orders. I never stole anything.","TWN":"我只是奉陛下之命去執行任務，沒有偷過鑰匙。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그럼 그 열쇠란 아티팩트는 지금 어디에 있지?","JPN":"じゃあ、その鍵というアーティファクトは今どこにあるの？","ENG":"Then where's that artifact called \\"the Key\\" now?","TWN":"那個叫鑰匙的人造神器現在在哪裡？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그건…… 기억이 나지 않아.","JPN":"それは……思い出せない。","ENG":"I... can't remember.","TWN":"這……我不記得。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"편리한 기억력이군.","JPN":"便利な記憶力だね。","ENG":"How convenient.","TWN":"不記得這句話還真好用。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"됐어. 떠올리려고 애쓰지 않아도 돼.","JPN":"いい。思い出そうと頑張らなくても。","ENG":"Never mind. Don't stress yourself out trying to remember it.","TWN":"沒關係，不需要努力去想。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"알고 있으니까. 제라드 큐리안이 자기 욕심 때문에 도둑질이나 할 인물이 아니라는 건.","JPN":"わかっているから。ジェラード・キュリアンが私欲のために泥棒するような人物じゃないってことは。","ENG":"Because I know Gerard Curian isn't someone who would steal for the sake of greed.","TWN":"因爲我知道，傑瑞德· 庫里安並不是會因為一己私慾而偷竊的人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런데 왜 주민들 앞에서 내 말을 막았지?","JPN":"だが、どうして住民の前で私の話をさえぎったんだ？","ENG":"Then why did you knock me out in front of all those people?","TWN":"那你爲什麼不讓我在大家面前解釋呢？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이곳 남부 국경의 주민들은 누구보다 오랫동안 침식으로 고통 받아 온 피해자들이야.","JPN":"ここ、南部国境の住民は誰よりも長く侵食によって苦しんできた被害者たちよ。","ENG":"The people here have been victims of the Corruption for longer than anywhere else.","TWN":"這邊國境南部的居民長久以來為侵蝕所苦。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"평생 동안 쌓인 응어리가 당신의 해명 몇 마디에 풀어질 리 없어. 화만 돋울 뿐이지.","JPN":"一生のわだかまりがあなたの釈明の一言ぐらいで解けるはずがない。もっと怒らせるだけ。","ENG":"The resentment they feel will not go away just because you said a few words. On the contrary, it'll only aggravate them.","TWN":"累積一輩子的怨氣，是不可能因為你的幾句話就消除的，反而只會火上澆油。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"열쇠만 있으면 낙원문을 다시 움직일 수 있는 건가? 그렇다면 반드시 되찾아 오겠다.","JPN":"鍵さえあれば楽園の門をまた動かせるのか？　それなら必ず取り戻して来る。","ENG":"Could Avalon's Gate start working again with the Key? If so, I have to go back to retrieve it.","TWN":"只要有鑰匙，樂園門就能重新啟動嗎？若是如此，那我一定會把鑰匙找回來。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그럴 필요 없어. 낙원문은 침식의 날에 무너졌거든.","JPN":"その必要はない。楽園の門は侵食の日に崩れたから。","ENG":"There's no need. Avalon's Gate collapsed on the Day of Corruption.","TWN":"沒必要，因為樂園門已在侵蝕之日崩塌，"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"낙원문에 대한 지식을 전수 받은 왕족들도 모두 사라졌으니, 다시 지을 수도 없지.","JPN":"楽園の門についての知識を授けられた王族も全ていなくなったから、建て直すこともできない。","ENG":"And because all the Royal Family members who inherited the knowledge of how to construct it are no longer alive, there's no chance of rebuilding it, either.","TWN":"知道樂園門知識的皇族也已消失，重建之日遙遙無期。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"들으면 들을수록 믿기지가 않는군…….","JPN":"聞けば聞くほど信じられんな……","ENG":"The more I hear about it, the more I can't believe it...","TWN":"我越聽越不敢相信我的耳朵……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식의 날로부터 대체 얼마나 많은 시간이 흐른 거지?","JPN":"侵食の日から一体どのくらいの時間が経ったんだ？","ENG":"How long has it been since the Day of Corruption?","TWN":"從侵蝕之日到現在，究竟已經經過多少時間？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"20년. 침식의 날은 내가 태어나기도 전에 있었던 일이야.","JPN":"20年。侵食の日は私が生まれる前の話。","ENG":"20 years. It was before I was even born.","TWN":"20年，侵蝕之日是我出生之前就發生的事情。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……자네는 완력이 성자 같던데, 혹시 발육이 빠른 게 능력인가?","JPN":"……君は腕力からすると聖者のようだが、もしかして発育が早いのも能力なのか？","ENG":"You seem strong like a Helgon. Is your ability rapid growth?","TWN":"……你的腕力跟聖者很像，你的特殊能力是發育迅速嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내가 빠른 게 아니라 당신이 느린 거야.","JPN":"私が早いんじゃなくて、あなたが遅いだけ。","ENG":"It's not that I'm fast, it's you who's slow.","TWN":"不是我快，而是你慢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고 지금은 아무도 성자라는 표현을 쓰지 않아. 우리 같은 사람들은 카운터라고 불리지.","JPN":"それから、今は誰も聖者という表現を使わない。私たちのような人はカウンターと呼ばれているよ。","ENG":"Also, people don't say \\"Helgon\\" these days. They call people like us \\"Counters\\".","TWN":"而且現在沒有人用聖者來形容，現在大家都用制裁者才稱呼我們這種人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"카운터……. 그러고 보니 피터도 자네를 그렇게 불렀지.","JPN":"カウンター……そういえばピーターも君をそう呼んでいたな。","ENG":"Counters... Come to think of it, Peter called you that too.","TWN":"制裁者……剛才好像彼得也是這樣稱呼你的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 진짜 큐리안인지 과대망상 환자인지는 몰라도, 우선 이것만은 확실히 해 둘게.","JPN":"あなたが本物のキュリアンなのか、それとも誇大妄想の患者かはわからないけど、これだけははっきりさせておく。","ENG":"I don't know if you are the real Curian or a patient suffering from grandiose delusions, but let's get one thing straight.","TWN":"雖然不知道你是真正的庫里安，還是只是有妄想症，不過有一點是可以肯定的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"큐리안은 아티팩트 <color=#ffd34c>열쇠</color>를 훔쳐가서 노르드나빅의 존속을 위협한 국가지명수배자야.","JPN":"キュリアンはアーティファクトの<color=#ffd34c>鍵</color>を盗み、ノルドナビックの存続を脅かした国家指名手配犯よ。","ENG":"Curian is a wanted criminal who stole the artifact key and threatened the continued existence of Nordnavik.","TWN":"就是庫里安是偷走人造神器<color=#ffd34c>鑰匙</color>，威脅諾爾德萊比存亡的國家通緝犯。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가…… 수배자라고?","JPN":"私が……手配犯だと？","ENG":"I'm... a wanted criminal?","TWN":"我是…… 通緝犯？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};